#include <bits/stdc++.h>
using namespace std;

const int N=1010,M=5.1e5,INF=1e8;

int n,a[N],f[N],s,S,T;
int head[N],ver[M],edge[M],nxt[M],tot=1;
int d[N],now[N];

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=w,nxt[tot]=head[u],head[u]=tot;
    ver[++tot]=u,edge[tot]=0,nxt[tot]=head[v],head[v]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(S),d[S]=1,now[S]=head[S];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==T)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==T)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d",&n);
    S=2*n+1,T=2*n+2;
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        add(i,n+i,1);
    }
    for(int i=1;i<=n;i++){
        f[i]=1;
        for(int j=1;j<i;j++)
            if(a[j]<=a[i])
                f[i]=max(f[i],f[j]+1);
        s=max(s,f[i]);
    }
    for(int i=1;i<=n;i++){
    	if(f[i]==1)
        	add(S,i,1);
        if(f[i]==s)
            add(i+n,T,1);
        for(int j=1;j<i;j++)
            if(a[j]<=a[i] && f[i]==f[j]+1)
                add(n+j,i,1);
    }
    printf("%d\n",s);
    if(s==1)
        printf("%d\n%d",n,n);
    else{
        int flow,max_flow=0;
        while(bfs())
            while(flow=Dinic(S,INF))
                max_flow+=flow;
        printf("%d\n",max_flow);
        for(int i=2;i<=tot;i+=2){
            if(ver[i^1]==S && (ver[i]==1 || ver[i]==n) || ver[i]==T && (ver[i^1]==n+1 || ver[i^1]==n+n))
                edge[i]=INF;
            if(ver[i^1]==1 && ver[i]==n+1 || ver[i^1]==n && ver[i]==n+n)
                edge[i]=INF;
        }
        while(bfs())
            while(flow=Dinic(S,INF))
                max_flow+=flow;
        printf("%d",max_flow);
    }
    return 0;
}
